const results = [];
const now = new Date();
const warningThreshold = new Date(now.getTime() + 60 * 60 * 1000); // 1 hour from now

for (const item of $input.all()) {
  const row = item.json;
  // Check if Open and SLA_Deadline exists
  if (row.Status && row.Status.includes('Open') && row.SLA_Deadline) {
    const deadline = new Date(row.SLA_Deadline);
    if (deadline < warningThreshold && deadline > now) {
      row.minutes_left = Math.round((deadline - now) / 60000);
      results.push({ json: row });
    }
  }
}
return results;

